/// <summary>
/// Represents the table of load ports for the ETGSPAIN model.
/// </summary>
public class ETGSPAINPurchLoadPortTable extends common
{    
}

Method.Source:
/// <summary>
/// Finds a record in the ETGSPAINPurchLoadPortTable.
/// </summary>
/// <param name="_loadPortId">The unique identifier for the load port.</param>
/// <param name="_forUpdate">Specifies if the record should be locked for update.</param>
/// <returns>Returns the found ETGSPAINPurchLoadPortTable record.</returns>
static ETGSPAINPurchLoadPortTable find(ETGSPAINPurchLoadPortId    _loadPortId,
                                    boolean             _forUpdate = false)
{
    ETGSPAINPurchLoadPortTable   ETGSPAINPurchLoadPortTable;

    if (_loadPortId)
    {
        if (_forUpdate)
        {
            ETGSPAINPurchLoadPortTable.selectForUpdate(_forUpdate);
        }

        select firstonly ETGSPAINPurchLoadPortTable
            where ETGSPAINPurchLoadPortTable.LoadPortId == _loadPortId;
    }

    return ETGSPAINPurchLoadPortTable;
}

/// <summary>
/// Checks if a record exists in the ETGSPAINPurchLoadPortTable.
/// </summary>
/// <param name="_loadPortId">The unique identifier for the load port.</param>
/// <returns>Returns true if the record exists, otherwise false.</returns>
static boolean exist(ETGSPAINPurchLoadPortId    _loadPortId)
{
    return _loadPortId && (select firstonly RecId from ETGSPAINPurchLoadPortTable
                                index hint LoadPortIdx
                                where ETGSPAINPurchLoadPortTable.LoadPortId == _loadPortId).RecId != 0;
}

/// <summary>
/// Performs a lookup for cities based on the load port's country and city.
/// </summary>
/// <param name="_ETGSPAINPurchLoadPortTable">The load port table to base the lookup on.</param>
/// <param name="_formControl">The form control triggering the lookup.</param>
public static void addressCityLookUp(ETGSPAINPurchLoadPortTable _ETGSPAINPurchLoadPortTable, FormControl _formControl)
{
    SysTableLookup          sysTableLookup              = SysTableLookup::newParameters(tableNum(LogisticsAddressCity), _formControl);

    Query                   query                       = new Query();
    QueryBuildDataSource    qbdsLogisticsAddressCity    = SysQuery::findOrCreateDataSource(query, tableNum(LogisticsAddressCity));;
    QueryBuildRange         qbrCountryRegionId          = SysQuery::findOrCreateRange(qbdsLogisticsAddressCity, fieldNum(LogisticsAddressCity, CountryRegionId));
    QueryBuildRange         qbrName                     = SysQuery::findOrCreateRange(qbdsLogisticsAddressCity, fieldNum(LogisticsAddressCity, Name));

    if (_ETGSPAINPurchLoadPortTable.CountryRegionId)
    {
        qbrCountryRegionId.value(_ETGSPAINPurchLoadPortTable.CountryRegionId);
    }

    if (_ETGSPAINPurchLoadPortTable.AdressCity)
    {
        qbrName.value(queryValue(_ETGSPAINPurchLoadPortTable.AdressCity));
    }

    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, Name));
    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, Description));
    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, StateId));
    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, CountyId));

    sysTableLookup.parmQuery(query);

    sysTableLookup.performFormLookup();
}
